(function() {
  'use strict';

  if (window.__igDownloadActive) return;
  window.__igDownloadActive = true;

  var PROCESSED_ATTR = 'data-ba-ig-dl';

  var STYLES = document.createElement('style');
  STYLES.textContent = [
    '.ba-ig-dl-bar{display:flex;gap:6px;padding:6px 12px;align-items:center}',
    '.ba-ig-btn{display:inline-flex;align-items:center;gap:4px;padding:6px 12px;font-size:13px;font-weight:600;color:#fff;background:#0095f6;border:none;border-radius:8px;cursor:pointer;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI",Roboto,sans-serif;transition:background .15s}',
    '.ba-ig-btn:hover{background:#1877f2}',
    '.ba-ig-btn--open{background:#262626;color:#fff}',
    '.ba-ig-btn--open:hover{background:#363636}',
    '.ba-ig-btn svg{width:14px;height:14px;fill:currentColor}'
  ].join('\n');
  document.head.appendChild(STYLES);

  var DL_SVG = '<svg viewBox="0 0 24 24"><path d="M12 15.575l-4.95-4.95 1.414-1.414L11 11.747V3h2v8.747l2.536-2.536 1.414 1.414L12 15.575zM5 19h14v-4h2v5a1 1 0 01-1 1H4a1 1 0 01-1-1v-5h2v4z"/></svg>';
  var OPEN_SVG = '<svg viewBox="0 0 24 24"><path d="M10 6v2H5v11h11v-5h2v6a1 1 0 01-1 1H4a1 1 0 01-1-1V7a1 1 0 011-1h6zm11-3v8h-2V6.413l-7.793 7.794-1.414-1.414L17.585 5H13V3h8z"/></svg>';

  function createDLButton(url, label) {
    var btn = document.createElement('button');
    btn.className = 'ba-ig-btn';
    btn.innerHTML = DL_SVG + ' ' + label;
    btn.addEventListener('click', function(e) {
      e.preventDefault();
      e.stopPropagation();
      var a = document.createElement('a');
      a.href = url;
      a.download = 'instagram_' + Date.now() + (label.toLowerCase().includes('video') ? '.mp4' : '.jpg');
      a.target = '_blank';
      a.rel = 'noopener';
      document.body.appendChild(a);
      a.click();
      a.remove();
    });
    return btn;
  }

  function createOpenButton(url) {
    var btn = document.createElement('button');
    btn.className = 'ba-ig-btn ba-ig-btn--open';
    btn.innerHTML = OPEN_SVG + ' Open';
    btn.addEventListener('click', function(e) {
      e.preventDefault();
      e.stopPropagation();
      window.open(url, '_blank');
    });
    return btn;
  }

  function getMediaFromArticle(article) {
    var result = { images: [], videos: [] };

    // Videos (posts, reels)
    var videos = article.querySelectorAll('video[src], video source[src]');
    videos.forEach(function(v) {
      var src = v.src || v.getAttribute('src');
      if (src && result.videos.indexOf(src) === -1) result.videos.push(src);
    });

    // Images (posts)
    var imgs = article.querySelectorAll('img[srcset], img[src]');
    imgs.forEach(function(img) {
      // Skip tiny icons, emojis, and profile pics in headers
      if (img.width < 50 || img.height < 50) return;
      var parent = img.closest('header');
      if (parent) return;

      var srcset = img.getAttribute('srcset');
      var bestSrc = '';
      if (srcset) {
        var parts = srcset.split(',').map(function(s) { return s.trim(); });
        var last = parts[parts.length - 1];
        bestSrc = last.split(' ')[0];
      } else {
        bestSrc = img.src;
      }
      if (bestSrc && bestSrc.indexOf('s150x150') === -1 && result.images.indexOf(bestSrc) === -1) {
        result.images.push(bestSrc);
      }
    });

    return result;
  }

  function processPost(article) {
    if (article.hasAttribute(PROCESSED_ATTR)) return;
    article.setAttribute(PROCESSED_ATTR, 'true');

    var media = getMediaFromArticle(article);
    if (media.images.length === 0 && media.videos.length === 0) return;

    var bar = document.createElement('div');
    bar.className = 'ba-ig-dl-bar';

    media.images.forEach(function(url, idx) {
      var label = media.images.length > 1 ? 'Photo ' + (idx + 1) : 'Photo';
      bar.appendChild(createDLButton(url, label));
      bar.appendChild(createOpenButton(url));
    });

    media.videos.forEach(function(url, idx) {
      var label = media.videos.length > 1 ? 'Video ' + (idx + 1) : 'Video';
      bar.appendChild(createDLButton(url, label));
      bar.appendChild(createOpenButton(url));
    });

    // Insert below the media section
    var section = article.querySelector('section');
    if (section) {
      section.parentElement.insertBefore(bar, section);
    } else {
      article.appendChild(bar);
    }
  }

  function processStories() {
    var storyContainer = document.querySelector('[role="presentation"] video[src], [role="dialog"] video[src]');
    if (storyContainer) {
      var parent = storyContainer.closest('[role="presentation"]') || storyContainer.closest('[role="dialog"]');
      if (parent && !parent.hasAttribute(PROCESSED_ATTR)) {
        parent.setAttribute(PROCESSED_ATTR, 'true');
        var bar = document.createElement('div');
        bar.className = 'ba-ig-dl-bar';
        bar.style.cssText = 'position:absolute;bottom:60px;left:50%;transform:translateX(-50%);z-index:9999;';
        bar.appendChild(createDLButton(storyContainer.src, 'Video'));
        bar.appendChild(createOpenButton(storyContainer.src));
        parent.style.position = 'relative';
        parent.appendChild(bar);
      }
    }

    var storyImg = document.querySelector('[role="presentation"] img[srcset], [role="dialog"] img[decoding="sync"]');
    if (storyImg && !storyImg.hasAttribute(PROCESSED_ATTR)) {
      storyImg.setAttribute(PROCESSED_ATTR, 'true');
      var srcset = storyImg.getAttribute('srcset');
      var bestSrc = storyImg.src;
      if (srcset) {
        var parts = srcset.split(',').map(function(s) { return s.trim(); });
        bestSrc = parts[parts.length - 1].split(' ')[0];
      }
      var imgParent = storyImg.closest('[role="presentation"]') || storyImg.closest('[role="dialog"]');
      if (imgParent) {
        var bar2 = document.createElement('div');
        bar2.className = 'ba-ig-dl-bar';
        bar2.style.cssText = 'position:absolute;bottom:60px;left:50%;transform:translateX(-50%);z-index:9999;';
        bar2.appendChild(createDLButton(bestSrc, 'Photo'));
        bar2.appendChild(createOpenButton(bestSrc));
        imgParent.style.position = 'relative';
        imgParent.appendChild(bar2);
      }
    }
  }

  function processProfilePicture() {
    var header = document.querySelector('header');
    if (!header || header.hasAttribute(PROCESSED_ATTR)) return;

    var avatar = header.querySelector('img[alt*="profile picture"], img[data-testid="user-avatar"]');
    if (!avatar) return;

    // Get full-size profile picture URL
    var src = avatar.src;
    if (!src) return;
    var fullSrc = src.replace(/\/s\d+x\d+\//, '/').replace(/\/c\d+\.\d+\.\d+\.\d+\//, '/');

    header.setAttribute(PROCESSED_ATTR, 'true');
    var bar = document.createElement('div');
    bar.className = 'ba-ig-dl-bar';
    bar.appendChild(createDLButton(fullSrc, 'Profile Pic'));
    bar.appendChild(createOpenButton(fullSrc));

    var avatarParent = avatar.closest('span') || avatar.parentElement;
    if (avatarParent && avatarParent.parentElement) {
      avatarParent.parentElement.appendChild(bar);
    }
  }

  function processAll() {
    document.querySelectorAll('article').forEach(processPost);
    processStories();
    processProfilePicture();
  }

  processAll();

  var observer = new MutationObserver(function() {
    processAll();
  });
  observer.observe(document.body, { childList: true, subtree: true });

  console.log('[Instagram Download Button] Active — download buttons added to posts, stories, and profiles.');
})();
